class EventualConsistentStore:
    def __init__(self):
        self.replicas = {}
        self.version = {}

    def write(self, key, value):
        # Write to all replicas asynchronously
        for replica_id in self.replicas:
            self.replicas[replica_id][key] = value
            self.version[key] = self.version.get(key, 0) + 1
        return True

    def read(self, key):
        # Read from any available replica (may be stale)
        for replica_id in self.replicas:
            if key in self.replicas[replica_id]:
                return self.replicas[replica_id][key]
        return None

    def sync(self, source_replica, target_replica):
        # Background sync process
        for key, value in self.replicas[source_replica].items():
            self.replicas[target_replica][key] = value

class StrongConsistentStore {
    private List<Replica> replicas;
    private int quorumSize;

    public void write(String key, String value) {
        // Write to quorum of replicas before acknowledging
        int written = 0;
        for (Replica replica : replicas) {
            if (replica.write(key, value)) {
                written++;
            }
            if (written >= quorumSize) break;
        }
        if (written < quorumSize) {
            throw new ConsistencyException("Write failed");
        }
    }

    public String read(String key) {
        // Read from quorum to ensure latest value
        Map<String, Integer> versions = new HashMap<>();
        for (Replica replica : replicas) {
            String value = replica.read(key);
            if (value != null) {
                versions.put(value, versions.getOrDefault(value, 0) + 1);
            }
        }
        // Return value with majority votes
        return versions.entrySet().stream()
            .max(Map.Entry.comparingByValue())
            .map(Map.Entry::getKey)
            .orElse(null);
    }
}
